import{_ as t,o as l,c as r,ag as e}from"./chunks/framework.BbyMWZAR.js";const k=JSON.parse('{"title":"Skills 是什么？和 Tool / Prompt 有何区别","description":"","frontmatter":{"title":"Skills 是什么？和 Tool / Prompt 有何区别","difficulty":"medium","tags":["skills","tool-calling","prompt","MCP"],"estimate":15},"headers":[],"relativePath":"domains/ai/qa/qa-04-skills-and-tool-use.md","filePath":"domains/ai/qa/qa-04-skills-and-tool-use.md","lastUpdated":1783504823000}'),s={name:"domains/ai/qa/qa-04-skills-and-tool-use.md"};function i(a,o,n,d,c,g){return l(),r("div",null,[...o[0]||(o[0]=[e('<h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>Cursor、Claude Code 等工具里常提到 <strong>Skills</strong>（技能包）。请解释 Skills 的概念，它与 Function Calling / Tools、以及长 System Prompt 的分工边界。</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>Tool / Function Calling</strong> 是模型 API 层的机制：声明一组函数 schema，模型在推理时输出 <code>name + arguments</code>，由<strong>运行时执行</strong>并回传结果。特点是 <strong>结构化、可校验、适合机器动作</strong>（查 API、跑命令、读 DB）。</p><p><strong>System Prompt / 指令</strong> 是告诉模型<strong>怎么想、怎么说话、遵守什么规则</strong>，通常每次请求都带上（或缓存前缀）。适合风格、安全策略、输出格式；但过长会占窗口、难版本化、难按需加载。</p><p><strong>Skills</strong>（在 IDE Agent 语境下）是介于两者之间的 <strong>可组合能力模块</strong>：</p><ul><li>以 <strong>独立文档/包</strong> 存在（如 <code>SKILL.md</code>），描述<strong>何时启用、步骤、约束、可用工具、示例</strong>；</li><li>由 <strong>路由层</strong> 根据用户意图或上下文 <strong>选择性注入</strong> prompt，而不是永远塞进 system；</li><li>常与人类可维护的工作流绑定（「写 PR」「查日志」「做 code review」），可版本管理、可团队共享。</li></ul><p>可以粗略类比：</p><table tabindex="0"><thead><tr><th>机制</th><th>类比</th><th>典型内容</th></tr></thead><tbody><tr><td>Tool</td><td>手</td><td>调 API、执行函数</td></tr><tr><td>System Prompt</td><td>性格与总规章</td><td>安全、格式、角色</td></tr><tr><td>Skill</td><td>岗位 SOP</td><td>场景化流程、检查清单、领域知识</td></tr></tbody></table><p><strong>为什么需要 Skills</strong></p><ul><li>一个全能 system prompt 会 <strong>又臭又长</strong>，且不同任务互相干扰。</li><li>Skills 实现 <strong>按需加载</strong>：用户说「帮我写飞书文档」→ 挂载 <code>lark-doc</code> skill；写代码 → 挂载 <code>frontend-design</code> skill。</li><li>便于 <strong>非工程师维护</strong> 业务 SOP（运营、法务审查流程）而不改代码。</li></ul><p><strong>前端 / 平台侧实现要点</strong></p><ol><li><strong>Skill 注册表</strong>：id、描述（给路由模型用）、文件路径、依赖工具列表；</li><li><strong>路由</strong>：用小模型或规则根据 query 选 0–N 个 skills（注意冲突与总 token）；</li><li><strong>注入</strong>：把 skill 正文拼进 system 或单独 <code>developer</code> 消息，并记录版本号便于回放；</li><li><strong>UI</strong>：可选展示「当前启用：xxx 技能」，让用户手动开关，提高可控性。</li></ol><p>Skills <strong>不替代</strong> Tool：skill 告诉模型「按什么流程用哪些工具」；真正执行仍在 tool runtime。没有 tool 的 skill 只是加强版 prompt 片段。</p><h2 id="追问-1-skill-和-mcp-server-提供的-resource-tool-会重复吗" tabindex="-1">追问 1：Skill 和 MCP Server 提供的 Resource/Tool 会重复吗？ <a class="header-anchor" href="#追问-1-skill-和-mcp-server-提供的-resource-tool-会重复吗" aria-label="Permalink to &quot;追问 1：Skill 和 MCP Server 提供的 Resource/Tool 会重复吗？&quot;">​</a></h2><h3 id="答" tabindex="-1">答 <a class="header-anchor" href="#答" aria-label="Permalink to &quot;答&quot;">​</a></h3><ul><li>MCP Server 暴露的是 <strong>可调用能力</strong>（tools）和 <strong>可读数据</strong>（resources）。</li><li>Skill 是 <strong>使用这些能力的说明书</strong>。一个 skill 可以写「先 <code>list_repos</code>，再 <code>read_file</code>」。</li><li>重复时以 <strong>单一事实来源</strong> 为准：tool schema 以 MCP 为准，skill 只写流程不写错参数名。</li><li>平台应避免同一动作既在 skill 里硬编码 curl，又注册同名 tool，造成模型困惑。</li></ul><h2 id="追问-2-如何测试一个-skill-是否「有效」" tabindex="-1">追问 2：如何测试一个 Skill 是否「有效」？ <a class="header-anchor" href="#追问-2-如何测试一个-skill-是否「有效」" aria-label="Permalink to &quot;追问 2：如何测试一个 Skill 是否「有效」？&quot;">​</a></h2><h3 id="答-1" tabindex="-1">答 <a class="header-anchor" href="#答-1" aria-label="Permalink to &quot;答&quot;">​</a></h3><ul><li><strong>离线</strong>：用固定 eval 集（输入 → 期望调用的 tool 序列 / 输出关键词），跑回归。</li><li><strong>在线</strong>：灰度发布 skill 版本，对比任务完成率、人工接管率、平均 token。</li><li><strong>可观测</strong>：日志记录 <code>skill_ids</code>、<code>tools_invoked</code>、<code>iteration_count</code>，定位「skill 太长导致超窗」等问题。</li><li>避免只测 demo 问句；要测 <strong>边界</strong>（缺权限、工具失败、用户中途改需求）。</li></ul><h2 id="追问-3-用户自定义-skill-有什么安全风险" tabindex="-1">追问 3：用户自定义 Skill 有什么安全风险？ <a class="header-anchor" href="#追问-3-用户自定义-skill-有什么安全风险" aria-label="Permalink to &quot;追问 3：用户自定义 Skill 有什么安全风险？&quot;">​</a></h2><h3 id="答-2" tabindex="-1">答 <a class="header-anchor" href="#答-2" aria-label="Permalink to &quot;答&quot;">​</a></h3><ul><li>恶意 skill 可诱导模型 <strong>泄露 system prompt、调用危险 tool、或社会工程用户</strong>。</li><li>缓解：自定义 skill 沙箱（禁止声明超出用户权限的 tool）、人工审核、仅团队内分享；</li><li>与 Prompt Injection 叠加时风险更高，需把用户提供的 skill 视为 <strong>不可信输入</strong>，与核心 system 指令分层隔离。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/engineer/handbook/domains/ai/RESOURCES">AI 应用 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://modelcontextprotocol.io/introduction" target="_blank" rel="noreferrer">Model Context Protocol (MCP)</a>：Skills / 外部工具与资源的标准化接入协议。</li><li><a href="https://docs.anthropic.com/en/docs/build-with-claude/tool-use" target="_blank" rel="noreferrer">Anthropic: Tool use</a>：模型侧 tool 选择与参数生成行为。</li><li><a href="https://spec.modelcontextprotocol.io/" target="_blank" rel="noreferrer">MCP Specification</a>：传输层、资源与工具抽象的规范细节。</li></ul>',26)])])}const u=t(s,[["render",i]]);export{k as __pageData,u as default};
